function currency(strings, ...values) {
  let result = "";
  strings.forEach((str, i) => {
    result += str;
    if (i < values.length) {
      result += "Rs " + values[i].toLocaleString();
    }
  });
  return result;
}

const price = 45000;
const tax = 8100;
const total = price + tax;

console.log(currency`Price: ${price}, Tax: ${tax}, Total: ${total}`);

